export const meta = {
  name: 'review-sts-exchange-error',
  description: 'Multi-lens review of the typed ExchangeError change in sts, with adversarial verification',
  phases: [
    { title: 'Review', detail: 'four review lenses over the diff' },
    { title: 'Verify', detail: 'adversarially verify each finding' },
  ],
}

const CONTEXT = `
# Change under review (branch sts-typed-exchange-error, commit 9ea266a)

The change introduces a typed error \`sts.ExchangeError\` returned by \`Client.Exchange\`
when the token endpoint replies with a structured RFC 6749 OAuth error. Previously
\`readAPIError\` returned a plain \`fmt.Errorf("token exchange: status %d: %s: %s", ...)\`.

## Full diff
\`\`\`diff
diff --git a/CHANGELOG.md b/CHANGELOG.md
@@
+## Unreleased
+### Added
+- \`sts.ExchangeError\` — a typed error returned by \`Client.Exchange\` when
+  the token endpoint replies with a structured RFC 6749 OAuth error.
+  Exposes the parsed \`Code\`, \`Description\`, and \`StatusCode\` so callers
+  can branch on the failure mode (e.g. \`errors.As\` + \`Code ==
+  "invalid_target"\`) instead of substring-matching the message. \`Error()\`
+  renders the same string as before, so message-matching callers are
+  unaffected; non-OAuth failures (network errors, non-JSON bodies) remain
+  plain wrapped errors.

diff --git a/sts/sts.go b/sts/sts.go
@@ readAPIError @@
+type ExchangeError struct {
+	StatusCode  int
+	Code        string
+	Description string
+}
+
+func (e *ExchangeError) Error() string {
+	if e.Description != "" {
+		return fmt.Sprintf("token exchange: status %d: %s: %s", e.StatusCode, e.Code, e.Description)
+	}
+	return fmt.Sprintf("token exchange: status %d: %s", e.StatusCode, e.Code)
+}
+
 func readAPIError(resp *http.Response) error {
 	apiErr, parseErr := oauthhttp.ReadOAuthError(resp)
 	if parseErr != nil {
 		return fmt.Errorf("token exchange: %w", parseErr)
 	}
-	code := oauthhttp.SanitizeDescription(apiErr.Error)
-	if desc := oauthhttp.SanitizeDescription(apiErr.ErrorDescription); desc != "" {
-		return fmt.Errorf("token exchange: status %d: %s: %s", resp.StatusCode, code, desc)
-	}
-	return fmt.Errorf("token exchange: status %d: %s", resp.StatusCode, code)
+	return &ExchangeError{
+		StatusCode:  resp.StatusCode,
+		Code:        oauthhttp.SanitizeDescription(apiErr.Error),
+		Description: oauthhttp.SanitizeDescription(apiErr.ErrorDescription),
+	}
 }
\`\`\`
A new test TestExchange_ReturnsTypedExchangeError was added (errors.As + field asserts + byte-for-byte Error() check).

## Key files (read them — do not trust this summary alone)
- /Users/nodo/work/entire/auth-go/sts/sts.go        (Exchange at ~205-297; readAPIError + ExchangeError at ~391-429; Exchange doc comment 205-210)
- /Users/nodo/work/entire/auth-go/sts/sts_test.go   (tests ~500-650)
- /Users/nodo/work/entire/auth-go/internal/oauthhttp/error.go    (ReadOAuthError: returns *OAuthErrorResponse only when Error non-empty)
- /Users/nodo/work/entire/auth-go/internal/oauthhttp/sanitize.go (SanitizeDescription: strips C0/C1/DEL, caps 512 runes, TrimSpace, appends … on truncate)
- /Users/nodo/work/entire/auth-go/refresh/refresh.go    (sibling readAPIError ~267: uses ErrInvalidGrant sentinel + fmt.Errorf, NO typed struct)
- /Users/nodo/work/entire/auth-go/deviceflow/deviceflow.go (sibling readAPIError ~486: uses errCodeToSentinel, NO typed struct)
- /Users/nodo/work/entire/auth-go/tokenmanager/tokenmanager.go (consumer; runExchange ~873 returns sts.Exchange err verbatim; comment ~465 mentions "invalid_target: audience is required")
- /Users/nodo/work/entire/auth-go/CLAUDE.md (CHANGELOG discipline)

## Verified facts (already run — do NOT re-run; trust these)
- go build ./... : PASS
- go vet ./sts/... : PASS
- go test ./sts/... : PASS
- golangci-lint run ./sts/... : 0 issues
- ReadOAuthError guarantees a returned non-nil *OAuthErrorResponse has non-empty .Error (so Code is never empty when ExchangeError is constructed via this path).
- The Exchange doc comment (sts.go ~205-210) still says callers "can match on the returned error message for known OAuth error codes" — written before the typed error existed.
- tokenmanager runExchange returns the sts error verbatim; tokenmanager_test.go ~642 fakes the error with errors.New("token exchange: status 400: invalid_target") and asserts substring "invalid_target".
`

const FINDINGS_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['findings'],
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['title', 'severity', 'location', 'claim', 'evidence', 'recommendation'],
        properties: {
          title: { type: 'string' },
          severity: { type: 'string', enum: ['blocker', 'high', 'medium', 'low', 'nit'] },
          location: { type: 'string', description: 'file:line or symbol' },
          claim: { type: 'string', description: 'the precise assertion being made' },
          evidence: { type: 'string', description: 'concrete code/spec basis' },
          recommendation: { type: 'string' },
        },
      },
    },
  },
}

const VERDICT_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['verdict', 'confidence', 'reasoning', 'adjustedSeverity'],
  properties: {
    verdict: { type: 'string', enum: ['confirmed', 'refuted', 'partial'] },
    confidence: { type: 'string', enum: ['high', 'medium', 'low'] },
    reasoning: { type: 'string' },
    adjustedSeverity: { type: 'string', enum: ['blocker', 'high', 'medium', 'low', 'nit', 'invalid'] },
  },
}

const LENSES = [
  {
    key: 'correctness-compat',
    prompt: `You are reviewing for CORRECTNESS and BACKWARD COMPATIBILITY only.
Focus: Does ExchangeError.Error() render byte-for-byte identically to the pre-change fmt.Errorf strings in BOTH branches (with and without description)? Pointer vs value receiver implications (only *ExchangeError implements error — can a caller accidentally get a value? can errors.As fail?). Is the returned error still unwrapped/wrapped consistently with how Exchange returns it (sts.go:263 returns readAPIError(resp) directly)? Edge cases: empty Code, empty Description, both empty. Does any existing test still hold? Does the change alter errors.Is/errors.As behavior for any existing caller (tokenmanager substring match, refresh ErrInvalidGrant)? Are there nil-deref or formatting hazards?`,
  },
  {
    key: 'api-design',
    prompt: `You are reviewing for API / ABSTRACTION DESIGN only.
Focus: ExchangeError is a NEW exported type in a pre-1.0 library. Evaluate: (a) Consistency with sibling packages — refresh and deviceflow expose errors via SENTINELS (ErrInvalidGrant, errCodeToSentinel) and fmt.Errorf, NOT a typed struct. sts now diverges. Is that divergence justified (sts has open-ended codes like invalid_target) and is it documented/acknowledged anywhere? Should refresh/deviceflow be unified or at least cross-referenced? (b) Exported mutable fields (StatusCode/Code/Description) vs accessors. (c) Should it implement Unwrap()/Is() to interop with sentinels or expose typed Code constants? (d) The Code field is the SANITIZED code, not the raw wire code — does sanitizing the very field callers are told to branch on (Code == "invalid_target") create a correctness trap for legitimate codes, or is it safe given valid RFC 6749 codes are pure ASCII? (e) Is exposing only the sanitized Description (losing the raw value) a problem for callers? (f) Forward-compat: adding fields later, struct vs pointer return.`,
  },
  {
    key: 'security',
    prompt: `You are reviewing for SECURITY only.
Focus: This is OAuth error handling on a public-client device-flow path. (a) Terminal-injection / log-injection: Code and Description are now EXPORTED fields. They are sanitized via SanitizeDescription (strips C0/C1/DEL, caps 512 runes). Is sanitization applied on the right path and complete? Could a caller reasonably assume exported fields are raw/safe and the opposite is true, or assume they are safe when they are not? (b) Does exposing StatusCode/Code/Description widen any information-disclosure surface vs the old opaque string? (c) Is there any path where an UNsanitized value reaches the struct (e.g. via ReadOAuthError fallback, parseErr branch)? (d) Does Error() re-introduce any injection that sanitization removed? (e) DoS: 512-rune cap — any unbounded field? Read sanitize.go and error.go to ground claims.`,
  },
  {
    key: 'tests-docs-changelog',
    prompt: `You are reviewing TEST COVERAGE, DOCUMENTATION, and CHANGELOG only.
Focus: (a) Test gaps — the new test covers the WITH-description branch. Is the no-description branch of Error() (Description=="") tested anywhere? Is there a test that the OLD callers (substring matching) still pass — and does the existing suite already cover this? Is there a test pinning that errors.As yields the pointer type and that StatusCode/Code survive sanitization? (b) Stale docs — the Exchange method doc comment (sts.go ~205-210) still tells callers to "match on the returned error message for known OAuth error codes" and does NOT mention ExchangeError. Flag staleness. (c) CHANGELOG — verify the entry is accurate (does Error() truly render identically? is the "non-OAuth failures remain plain wrapped errors" claim true per readAPIError's parseErr branch?), under ## Unreleased per CLAUDE.md discipline, and describes a delta since v0.4.0. (d) Should tokenmanager (which has an "invalid_target" comment and verbatim error passthrough) be updated to use the new typed error, or is leaving it a documented follow-up?`,
  },
]

phase('Review')
const results = await pipeline(
  LENSES,
  (lens) => agent(`${CONTEXT}\n\n---\n\n${lens.prompt}\n\nReturn ONLY findings genuinely supported by reading the actual files. No filler. If the change is clean on your lens, return an empty findings array. Prefer few high-signal findings over many weak ones.`,
    { label: `review:${lens.key}`, phase: 'Review', schema: FINDINGS_SCHEMA }),
  (review, lens) => parallel((review.findings || []).map((f) => () =>
    agent(`${CONTEXT}\n\n---\n\nA reviewer (lens: ${lens.key}) raised this finding about the sts ExchangeError change. Your job is to ADVERSARIALLY VERIFY it — try to REFUTE it by reading the actual code/spec. Default to 'refuted' if the claim is not concretely substantiated by the files.\n\nFINDING:\ntitle: ${f.title}\nseverity: ${f.severity}\nlocation: ${f.location}\nclaim: ${f.claim}\nevidence: ${f.evidence}\nrecommendation: ${f.recommendation}\n\nDecide: is this real, and is the severity right? A finding is only 'confirmed' if a competent maintainer would act on it. Stylistic/opinion-only items with no concrete cost are 'low' or 'nit' at most. Adjust severity honestly.`,
      { label: `verify:${lens.key}:${(f.title || '').slice(0, 28)}`, phase: 'Verify', schema: VERDICT_SCHEMA })
      .then((v) => ({ ...f, lens: lens.key, verdict: v }))
      .catch(() => null)
  )),
)

const all = results.flat().filter(Boolean)
const surviving = all.filter((f) => f.verdict && f.verdict.verdict !== 'refuted' && f.verdict.adjustedSeverity !== 'invalid')
const refuted = all.filter((f) => !surviving.includes(f))

log(`Findings raised: ${all.length}; survived verification: ${surviving.length}; refuted: ${refuted.length}`)

return {
  surviving: surviving.map((f) => ({
    lens: f.lens, title: f.title, location: f.location,
    rawSeverity: f.severity, adjustedSeverity: f.verdict.adjustedSeverity,
    verdict: f.verdict.verdict, confidence: f.verdict.confidence,
    claim: f.claim, evidence: f.evidence, recommendation: f.recommendation,
    verifierReasoning: f.verdict.reasoning,
  })),
  refuted: refuted.map((f) => ({
    lens: f.lens, title: f.title, rawSeverity: f.severity,
    why: f.verdict ? f.verdict.reasoning : 'verifier errored',
  })),
}

